(function() {
  const rawText = ($json.content?.parts?.[0]?.text || '').replace(/```html|```/g, '');
  if (!rawText) return { error: 'La IA no devolvió contenido' };

  // ── Meta descripción
  const metaMatch = rawText.match(/<!--METADESC:([\s\S]*?)-->/);
  const excerpt = metaMatch ? metaMatch[1].trim() : '';

  // ── Extraer el H1 que escribió la IA
  const h1Match = rawText.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
  const titleFromAI = h1Match 
    ? h1Match[1].replace(/<[^>]+>/g, '').trim()  // quita cualquier tag HTML interno
    : '';

  // ── Fallback si la IA no generó H1
  const software = $('Supabase Leer Software').item.json;
  const year = new Date().getFullYear();
  const title = titleFromAI || `${software.name}: análisis y opiniones reales (${year})`;

  // ── Limpiar HTML (Asegurar que <script> sobrevive para los schemas)
  const content = rawText
    .replace(/<!--METADESC:[\s\S]*?-->/g, '')
    .replace(/[\s\S]*?(?=<div|<section|<style|<script)/i, '')
    .replace(/<\/html>/gi, '')
    .trim();

  return {
    title:         title,
    slug:          software.slug || '',
    content:       content,
    excerpt:       excerpt,
    status:        'publish',
    software_id:   software.id,
    software_name: software.name,
    website_url:   software.website_url
  };
})()
}}

