const MIN_WORDS = 1000;
const inputItems = $input.all();

function countWords(text) {
  return text.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').filter(Boolean).length;
}
function countMatches(text, regex) {
  const matches = text.match(regex);
  return matches ? matches.length : 0;
}

return inputItems.map((item) => {
  const modelText = item.json.content?.parts?.[0]?.text ?? '';
  const cleaned = modelText.replace(/```html|```/g, '').trim();
  const reasons = [];

  if (!cleaned) reasons.push('empty_content');
  if (/COPIA_EXACTA_/i.test(cleaned)) reasons.push('placeholder_detected_copia_exacta');
  if (/CONTENIDO_DE_ANALISIS_LIBRE_/i.test(cleaned)) reasons.push('placeholder_base_no_reemplazado');
  if (countWords(cleaned) < MIN_WORDS) reasons.push('low_word_count:' + countWords(cleaned));
  if (countMatches(cleaned, /<h1\b/gi) !== 1) reasons.push('invalid_h1_count');
  if (!/"@type"\s*:\s*"FAQPage"/i.test(cleaned)) reasons.push('missing_faq_schema');

  const faqCount = countMatches(cleaned, /<details class="bsw-faq-item"/gi);
  if (faqCount < 8) {
    reasons.push('few_faqs_' + faqCount);
  }

  const score = Math.max(0, 100 - reasons.length * 20);
  const isPublishable = reasons.length === 0;

  if (!isPublishable) {
    throw new Error(`Quality gate blocked publish. score=${score}; reasons=${reasons.join(',')}`);
  }

  return { json: { ...item.json, qa_result: { is_publishable: isPublishable, score, reasons } } };
});

